using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class ReportFunction
{
    [FunctionName("GetReportData")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var parameters = req.Query.ToDictionary(x => x.Key, x => x.Value.ToString());
            
            var sqlQuery = BuildDynamicQuery(parameters);
            
            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(sqlQuery, connection))
                {
                    var results = new List<Dictionary<string, object>>();
                    
                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }
                    
                    return new OkObjectResult(results);
                }
            }
        }
        catch (Exception ex)
        {
            log.LogError($"Error executing query: {ex.Message}");
            return new StatusCodeResult(500);
        }
    }
    
    private static string BuildDynamicQuery(Dictionary<string, string> parameters)
    {
        var baseQuery = "SELECT * FROM ReportData WHERE 1=1";
        var conditions = new List<string>();
        
        foreach (var param in parameters)
        {
            if (!string.IsNullOrEmpty(param.Value) && param.Key != "code")
            {
                var columnName = param.Key;
                var value = param.Value.Replace("'", "''");
                
                if (columnName.EndsWith("_min"))
                {
                    var actualColumn = columnName.Substring(0, columnName.Length - 4);
                    conditions.Add($"[{actualColumn}] >= '{value}'");
                }
                else if (columnName.EndsWith("_max"))
                {
                    var actualColumn = columnName.Substring(0, columnName.Length - 4);
                    conditions.Add($"[{actualColumn}] <= '{value}'");
                }
                else if (columnName.EndsWith("_like"))
                {
                    var actualColumn = columnName.Substring(0, columnName.Length - 5);
                    conditions.Add($"[{actualColumn}] LIKE '%{value}%'");
                }
                else
                {
                    conditions.Add($"[{columnName}] = '{value}'");
                }
            }
        }
        
        if (conditions.Any())
        {
            baseQuery += " AND " + string.Join(" AND ", conditions);
        }
        
        return baseQuery;
    }
